#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}V;
V v3(float a,float b,float c){V v={a,b,c};return v;}
V add(V a,V b){return v3(a.x+b.x,a.y+b.y,a.z+b.z);}
V sub(V a,V b){return v3(a.x-b.x,a.y-b.y,a.z-b.z);}
V mul(V a,float s){return v3(a.x*s,a.y*s,a.z*s);}
float dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
V nrm(V a){return mul(a,1.f/sqrtf(dot(a,a)));}
int sp(V o,V d,V c,float r,float*t,V*p,V*n){
 V oc=sub(o,c);float a=dot(d,d),b=2*dot(oc,d),e=dot(oc,oc)-r*r,ds=b*b-4*a*e;
 if(ds<=0)return 0;float sq=sqrtf(ds),t1=(-b-sq)/(2*a);
